import { Scissors, ChevronLeft, User, LogOut, Save, Database } from 'lucide-react';

export default function Header({ 
  title, 
  subtitle, 
  onBack, 
  user, 
  onLogout, 
  steps, 
  onSave, 
  saving, 
  saveMsg 
}) {
  return (
    <header className="sticky top-0 z-50 bg-[#050505]/80 backdrop-blur-xl border-b border-white/5 shadow-lg shadow-black/20">
      <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">

        {/* GAUCHE: Retour + Titre */}
        <div className="flex items-center gap-4 flex-1 min-w-0">
          {onBack && (
            <button 
              onClick={onBack}
              className="p-2 -ml-2 rounded-lg text-slate-400 hover:text-white hover:bg-white/5 transition-all duration-300 hover:-translate-x-1"
            >
              <ChevronLeft className="w-6 h-6" />
            </button>
          )}

          <div className="flex items-center gap-3 min-w-0 cursor-pointer" onClick={() => !onBack && window.location.reload()}>
            <div className="w-9 h-9 bg-gradient-to-br from-orange-500 to-red-600 rounded-xl flex items-center justify-center shadow-lg shadow-orange-900/30 flex-shrink-0 transform hover:scale-105 transition-transform">
              <Scissors className="w-5 h-5 text-white" />
            </div>

            <div className="min-w-0">
              <h1 className="text-lg font-black text-white leading-tight truncate tracking-tight">PanelCut <span className="text-orange-500">Pro</span></h1>
              {subtitle && <p className="text-[10px] text-slate-400 font-medium uppercase tracking-wider truncate">{subtitle}</p>}
            </div>
          </div>
        </div>

        {/* CENTRE: Étapes (Stepper) */}
        {steps && steps.length > 0 && (
          <div className="hidden md:flex items-center gap-2 absolute left-1/2 -translate-x-1/2 bg-[#0a0a0a]/50 px-4 py-1.5 rounded-full border border-white/5 backdrop-blur-sm">
            {steps.map((step, idx) => (
              <div key={idx} className="flex items-center">
                <div className={`flex items-center gap-2 px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider transition-all duration-300 ${
                  step.active 
                    ? 'bg-orange-500 text-white shadow-lg shadow-orange-900/40 scale-105' 
                    : 'bg-transparent text-slate-500'
                }`}>
                  <span className={`w-4 h-4 rounded-full flex items-center justify-center text-[9px] ${
                    step.active ? 'bg-white/20' : 'bg-white/10 border border-white/10'
                  }`}>
                    {idx + 1}
                  </span>
                  <span className="hidden lg:inline">{step.label}</span>
                </div>
                {idx < steps.length - 1 && (
                  <div className={`w-6 h-0.5 mx-1 rounded-full transition-colors duration-300 ${
                    step.active ? 'bg-orange-500/50' : 'bg-white/5'
                  }`}></div>
                )}
              </div>
            ))}
          </div>
        )}

        {/* DROITE: Actions + Utilisateur */}
        <div className="flex items-center gap-3 flex-1 justify-end">

          {/* Message de sauvegarde */}
          {(saveMsg || saving) && (
            <div className={`hidden sm:flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold transition-all animate-fade-in ${
              saveMsg?.includes('✓') ? 'bg-green-500/10 text-green-400 border border-green-500/20' : 'bg-blue-500/10 text-blue-400 border border-blue-500/20'
            }`}>
              {saving ? <Database className="w-3.5 h-3.5 animate-spin" /> : <Save className="w-3.5 h-3.5" />}
              {saving ? 'Sauvegarde...' : saveMsg}
            </div>
          )}

          {/* Bouton Sauvegarder (si fourni) */}
          {onSave && !saving && (
            <button 
              onClick={onSave}
              className="hidden sm:flex items-center gap-2 bg-white/10 hover:bg-orange-500 hover:text-white text-slate-300 px-4 py-2 rounded-lg text-xs font-bold transition-all duration-300 border border-white/10 hover:border-orange-500 hover:shadow-lg hover:shadow-orange-900/30 transform hover:-translate-y-0.5"
            >
              <Save className="w-4 h-4" />
              <span>Sauvegarder</span>
            </button>
          )}

          {/* Séparateur */}
          {(onSave || user) && <div className="w-px h-6 bg-white/10 hidden sm:block"></div>}

          {/* Profil Utilisateur */}
          {user ? (
            <div className="group relative flex items-center gap-2 bg-white/5 hover:bg-white/10 border border-white/5 rounded-full pl-1 pr-3 py-1 transition-all duration-300 cursor-pointer">
              <div className="w-7 h-7 bg-gradient-to-tr from-blue-500 to-purple-600 rounded-full flex items-center justify-center text-xs font-bold text-white shadow-inner ring-2 ring-white/10 group-hover:ring-orange-500/50 transition-all">
                {user.email ? user.email[0].toUpperCase() : 'U'}
              </div>
              <span className="text-xs font-medium text-slate-300 group-hover:text-white max-w-[100px] truncate hidden sm:inline">
                {user.email?.split('@')[0]}
              </span>

              {onLogout && (
                <button 
                  onClick={onLogout}
                  className="ml-1 p-1.5 text-slate-500 hover:text-red-400 hover:bg-red-500/10 rounded-full transition-colors opacity-0 group-hover:opacity-100"
                  title="Déconnexion"
                >
                  <LogOut className="w-3.5 h-3.5" />
                </button>
              )}
            </div>
          ) : (
             <div className="w-8 h-8 bg-white/5 rounded-full flex items-center justify-center border border-white/5">
               <User className="w-4 h-4 text-slate-500" />
             </div>
          )}
        </div>

      </div>
    </header>
  );
}
